-- Podcast grouping entity + nullable Episode.podcastId, and the seeded
-- team catalog for the creation wizard's verticals. Purely additive:
-- existing Episode rows get NULL podcastId; seeded League/Team rows use
-- ON CONFLICT DO NOTHING and "seed:" ids so ingestion-provider rows
-- ("sio:...") are never touched. IF NOT EXISTS keeps re-runs idempotent.

CREATE TABLE IF NOT EXISTS "Podcast" (
    "id" TEXT NOT NULL,
    "name" TEXT NOT NULL,
    "cadence" TEXT NOT NULL,
    "scheduleDays" TEXT[] DEFAULT ARRAY[]::TEXT[],
    "verticals" TEXT[] DEFAULT ARRAY[]::TEXT[],
    "teams" TEXT[] DEFAULT ARRAY[]::TEXT[],
    "segmentCount" INTEGER NOT NULL DEFAULT 3,
    "hostIds" TEXT[] DEFAULT ARRAY[]::TEXT[],
    "owner" TEXT NOT NULL DEFAULT 'listener',
    "lastAutoGeneratedDate" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" TIMESTAMP(3) NOT NULL,

    CONSTRAINT "Podcast_pkey" PRIMARY KEY ("id")
);

CREATE INDEX IF NOT EXISTS "Podcast_cadence_idx" ON "Podcast"("cadence");

ALTER TABLE "Episode" ADD COLUMN IF NOT EXISTS "podcastId" TEXT;

CREATE INDEX IF NOT EXISTS "Episode_podcastId_idx" ON "Episode"("podcastId");

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'Episode_podcastId_fkey'
  ) THEN
    ALTER TABLE "Episode" ADD CONSTRAINT "Episode_podcastId_fkey"
      FOREIGN KEY ("podcastId") REFERENCES "Podcast"("id") ON DELETE SET NULL ON UPDATE CASCADE;
  END IF;
END $$;

